/**
 * Scroll position manager: saves the topmost visible item ID,
 * restores by scrolling that item into view.
 */
var STORAGE_KEY = 'react-hn-scroll'

function escapeSelector(str) {
  if (typeof CSS !== 'undefined' && CSS.escape) {
    return CSS.escape(str)
  }
  return String(str).replace(/[\\'"[\]]/g, '\\$&')
}

/**
 * Get the ID of the topmost visible ListItem in the viewport.
 */
function getTopVisibleItemId() {
  var items = document.querySelectorAll('.ListItem[data-id]')
  for (var i = 0; i < items.length; i++) {
    var rect = items[i].getBoundingClientRect()
    if (rect.bottom > 0 && rect.top < window.innerHeight) {
      return items[i].getAttribute('data-id')
    }
  }
  return null
}

/**
 * Save the topmost visible item ID.
 */
function savePosition(routeKey) {
  var itemId = getTopVisibleItemId()
  if (!itemId) return
  try {
    window.sessionStorage.setItem(STORAGE_KEY + ':' + routeKey, itemId)
  } catch (e) {}
}

/**
 * Restore scroll position by finding the saved item and scrolling it into view.
 * @returns {Function} cancel function
 */
function restorePosition(routeKey) {
  var cancelled = false
  var highlightTimer = null

  function cancel() {
    cancelled = true
    if (highlightTimer) {
      clearTimeout(highlightTimer)
      highlightTimer = null
    }
  }

  var itemId
  try {
    itemId = window.sessionStorage.getItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {
    return cancel
  }
  if (!itemId) return cancel

  // Clear immediately so a page refresh doesn't replay it
  clearPosition(routeKey)

  var escaped = escapeSelector(itemId)
  var attempts = 0

  function doRestore() {
    if (cancelled) return

    var el = document.querySelector('.ListItem[data-id="' + escaped + '"]')
    if (el) {
      el.scrollIntoView({block: 'start'})
      // Small offset so it's not flush against the top
      window.scrollBy(0, -6)

      el.classList.add('ListItem--scroll-restore')
      highlightTimer = setTimeout(function() {
        if (!cancelled) {
          el.classList.remove('ListItem--scroll-restore')
        }
      }, 2500)
      return
    }

    // Item not in DOM yet (loading from Firebase), retry
    attempts++
    if (attempts < 40) {
      setTimeout(doRestore, 80)
    }
  }

  // Wait one paint for React to render
  requestAnimationFrame(function() {
    if (!cancelled) doRestore()
  })

  return cancel
}

function clearPosition(routeKey) {
  try {
    window.sessionStorage.removeItem(STORAGE_KEY + ':' + routeKey)
  } catch (e) {}
}

export default {
  savePosition,
  restorePosition,
  clearPosition
}
